        PNINDEX: SDAI.LIST<SDAI.INTEGER>/*[0:?]*/ , 
        TRIANGLE_STRIPS: SDAI.LIST<SDAI.LIST<SDAI.INTEGER>/*[3:?]*/ >/*[0:?]*/ , 
        TRIANGLE_FANS: SDAI.LIST<SDAI.LIST<SDAI.INTEGER>/*[3:?]*/ >/*[0:?]*/ 
      ) {

        self._pnindex = 
        SDAI.LIST<SDAI.INTEGER>(from: PNINDEX.asSwiftType, 
          bound1:SDAI.UNWRAP(0), bound2:(nil as SDAI.INTEGER?))
        self._triangle_strips = 
        SDAI.LIST<SDAI.LIST<SDAI.INTEGER>>(from: TRIANGLE_STRIPS.asSwiftType, 
          bound1:SDAI.UNWRAP(0), bound2:(nil as SDAI.INTEGER?))
        self._triangle_fans = 
        SDAI.LIST<SDAI.LIST<SDAI.INTEGER>>(from: TRIANGLE_FANS.asSwiftType, 
          bound1:SDAI.UNWRAP(0), bound2:(nil as SDAI.INTEGER?))

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( PNINDEX: original._pnindex, TRIANGLE_STRIPS: original._triangle_strips, TRIANGLE_FANS: original._triangle_fans )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 3
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: SDAI.LIST<SDAI.INTEGER>.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]PNINDEX for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverRequiredParameter(as: SDAI.LIST<SDAI.LIST<
          SDAI.INTEGER>>.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]TRIANGLE_STRIPS for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p2) = exchangeStructure.recoverRequiredParameter(as: SDAI.LIST<SDAI.LIST<
          SDAI.INTEGER>>.self, from: parameters[2])
        else { exchangeStructure.add(errorContext: "while recovering parameter [2]TRIANGLE_FANS for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( PNINDEX: p0, TRIANGLE_STRIPS: p1, TRIANGLE_FANS: p2 )
      }
    }
  }
}
